-- 1. Xóa bảng cũ nếu tồn tại để tránh lỗi Msg 2714
IF OBJECT_ID('dbo.products', 'U') IS NOT NULL 
BEGIN
    -- Xóa các bảng đang tham chiếu đến products trước nếu cần (ví dụ: order_details, cart_details)
    -- ALTER TABLE order_details DROP CONSTRAINT IF EXISTS FK_order_details_products_product_id;
    DROP TABLE dbo.products;
END
GO

-- 2. Tạo bảng products với cấu trúc chuẩn
CREATE TABLE products
(
    Id              uniqueidentifier                                NOT NULL
        constraint PK_products primary key,
    -- COLLATE phải đứng trước NOT NULL
    name            nvarchar(255) collate Latin1_General_CI_AI  NOT NULL,
    description     nvarchar(max) collate Latin1_General_CI_AI,
    quantity        int       default 0                               NOT NULL,
    original_price  int       default 0                               NOT NULL,
    sale_price      int       default 0                               NOT NULL,
    category_id     int       default 0                               NOT NULL
        constraint FK_products_categories_category_id
            references categories
            on delete cascade,
    brand_id        int       default 0                               NOT NULL
        constraint FK_products_brands_brand_id
            references brands
            on delete cascade,
    unit_id         int       default 0                               NOT NULL
        constraint FK_products_units_unit_id
            references units
            on delete cascade,
    is_active       bit       default CONVERT([bit], 0)               NOT NULL,
    created_at      datetime2 default '0001-01-01T00:00:00.0000000' NOT NULL,
    deleted_at      datetime2,
    status_id       int       default 0                               NOT NULL
        constraint FK_products_product_statuses_status_id
            references product_statuses
            on delete cascade,
    modified_at     datetime2,
    thumbnail       nvarchar(255),
    -- Thêm cột version kiểu varbinary để chứa dữ liệu hex từ script của bạn
    version         varbinary(8)
)
GO

-- 3. Tạo các Index để tối ưu truy vấn
CREATE INDEX IX_products_brand_id ON products (brand_id)
GO
CREATE INDEX IX_products_category_id ON products (category_id)
GO
CREATE INDEX IX_products_unit_id ON products (unit_id)
GO
CREATE INDEX IX_products_status_id ON products (status_id)
GO

