INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'BFED3129-2B8B-4460-9B23-1130C9F3DCFB', N'Sữa Kid Essentials 800g cho các bé 1 - 10 tuổi', N'<h2><strong>Sữa Kid Essentials 800g cho bé 1-10 tuổi hỗ trợ tăng cân</strong></h2><p>Sữa Kid Essentials 800g hương vani phù hợp với các bé biếng ăn,&nbsp;<a href="https://www.kidsplaza.vn/tag/sua-tang-can-cho-be" rel="noopener noreferrer" target="_blank">sữa giúp bé&nbsp;tăng cân</a>&nbsp;trong độ tuổi từ 1-10 tuổi. Hãy cho bé dùng ngay sữa bột Kid Essentials Thụy Sĩ với thành phần 27 vitamin, khoáng chất thiết yếu cho trẻ, tinh bột, men tiêu hóa chống táo bón, củng cố hệ tiêu hóa cho trẻ nhỏ.</p><p><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-khac/sua-kid-essentials-800g-1a.jpg"></p><p><em>Sữa Kid Essential 800g cho bé 1-10 tuổi chậm tăng cân</em></p><p><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-khac/sua-kid-essentials-800g-2a.jpg"></p><p><em>Sữa Kid Essential 800g bổ sung các chất dinh dưỡng cho bé phát triển toàn diện về thể chất</em></p>', 0, 125000, 25000, 9, 4, 1, 1, N'2024-07-08 00:37:54.8895686', null, 2, N'2024-07-24 04:35:19.0425852', N'https://i.imgur.com/TucAON3.jpeg', 0x0000000000003AD7);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'05CC88F0-322C-4D8C-AF52-168B98E7E162', N'Tên sản phẩm4.558276200456479', N'string', 1, 10000, 10000, 1, 1, 1, 0, N'2024-07-12 10:54:54.5368339', N'2024-07-23 02:57:55.0537723', 1, N'2024-07-23 02:57:55.2005744', N'https://placehold.co/200', 0x00000000000039BD);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'A843237A-D2D0-43C1-BD96-1C231E2DFA53', N'Sữa Nan Supreme số 1 5-HMO 800g New 0-6M', N'<p><em>"Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ"</em></p><h2><strong>Sữa Nan Supremepro&nbsp;800g New cho bé từ 0 đến 6 tháng tuổi</strong></h2><p><strong>Sữa Nan cho bé</strong>&nbsp;Supreme số 1 HMO 5 800g New từ 0 đến 6M là sản phẩm dinh dưỡng công thức từ Thụy Sĩ,&nbsp;bổ sung các dưỡng chất thiết yếu giúp trẻ tăng cường sức đề kháng, dễ tiêu hoá, dễ hấp thu và phòng ngừa nguy cơ dị ứng (chàm sữa).&nbsp;</p><p><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-nan/sua-nan-supreme-s1-5-hmo-800g-thuy-si-new-5.jpg"></p><p><em>Sữa Nan Supreme Số 1 5HMO 800g New</em></p><h3><strong>Thành phần của sữa Nan Supreme số 1 5-HMO 800g New</strong></h3><p>Thành phẩn chính&nbsp;có trong&nbsp;<strong>sữa Nan Supreme</strong>&nbsp;số 1 5-HMO 800g New:&nbsp;</p><p><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-nan/sua-nan-supreme-s1-5-hmo-400g-thuy-si-new-4.jpg"></p><h3><strong>Công dụng&nbsp;của sữa Nan Supreme số 1 5-HMO 800g New:</strong></h3><p><strong>Sản phẩm sữa cho bé Nan Supreme số 1 800g New</strong>&nbsp;với công thức đầu tiên bổ sung 5 dưỡng chất<strong>&nbsp;(2’FL, DFL, LNT, 3’SL, 6’SL)</strong>&nbsp;giúp tăng cường sức đề kháng và giúp bé phát triển toàn diện.</p><p><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-nan/sua-nan-supreme-s1-5-hmo-400g-thuy-si-new-6.jpg"></p><p>Sản phẩm sữa có chứa chất&nbsp;đạm chất lượng OPTIPRO thủy phân một phần (HA)&nbsp;<strong>giúp trẻ&nbsp;dễ tiêu hóa, hấp thu và phòng ngừa nguy cơ dị ứng (chàm sữa).</strong></p><p><strong>Sữa Nan Supreme số 1 New 800g chứa&nbsp;</strong>lợi khuẩn Bifidus BL hỗ trợ sức đề kháng giúp và ngăn ngừa sự phát triển của vi khuẩn không có lợi hoặc gây bệnh cho trẻ.</p><p>Bên cạnh đó sữa Nan Supreme số 1 800g bổ sung DHA – ARA: Hỗ trợ tốt cho bé&nbsp;<strong>phát triển trí não và thị lực.</strong></p>', 9999, 635000, 40000, 4, 4, 1, 1, N'2024-06-24 11:12:56.0000000', null, 1, N'2024-07-23 06:01:22.8590526', N'https://i.imgur.com/hyZlrpE.jpeg', 0x0000000000003A3C);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'8FBE17A4-A34C-4648-8DD7-1E345C8F3F6A', N'Sữa Frisolac Gold Pro số 3 800g cho bé 1-3 tuổi', N'<p><em>Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ</em></p><p><strong>Sữa Frisolac Gold&nbsp;Pro 3&nbsp;</strong>là sản phẩm nhập khẩu 100% từ châu Âu với chất lượng được&nbsp;kiểm chứng qua công nghệ&nbsp;<strong>TrackEasy.&nbsp;</strong>Sữa Frisolac Gold Pro được sản xuất trên dây chuyền hiện đại, cao cấp tại Hà Lan.</p><p>Sữa Frisolac Gold Pro số 3 với công nghệ TrackEasy mới này sẽ giúp mẹ hiểu rõ hơn về quy trình kiểm tra chất lượng được thực hiện ở từng bước trong hành trình sản xuất của sản phẩm – từ nông trại Châu Âu cho đến khi cập bến tại Việt Nam.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Frisolac/sua-bot-frisolac-gold-pro-so-3-800g-cho-be-1-3-tuoi-a.jpg"></em></p><p><em>Sữa Frisolac Gold Pro số 3 800g cho bé 1-3 tuổi bao bì mới</em></p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/SEO/Sua-cho-be/sua-frisolac-gold-pro-3-800g-cho-be-1-3-tuoi.jpg"></em></p><p><em>Sữa Frisolac Gold Pro số 3 800g cho bé 1-3 tuổi bao bì cũ</em></p><p>&nbsp;</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Frisolac/sua-bot-frisolac-gold-pro-so-3-800g-cho-be-1-3-tuoi-c.jpg"></em></p><p><em>Thành phần dinh dưỡng có trong sữa Frisolac Gold Pro số 3 800g</em></p>', 100, 660000, 0, 7, 6, 1, 1, N'2024-07-04 13:00:03.0000000', null, 1, N'2024-07-23 03:02:10.4167062', N'https://i.imgur.com/Zk0oHbj.jpeg', 0x00000000000039C3);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'5C255DB1-6813-4C2D-BC74-1EAA7A500F45', N'Sữa Morinaga Chilmil số 2 320g cho bé 6M-36M', N'<p><em>CHÚ Ý: "Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ".</em></p><h3><strong>Sữa bột&nbsp;với thành phần lactoferrin giúp tăng cường sức khỏe hệ miễn dịch</strong></h3><p>Lactoferrin là một dưỡng chất có nhiều trong sữa mẹ, đặc biệt là sữa non, đóng vai trò làm kháng thể giúp kháng khuẩn, kháng virus, điều hoà hệ miễn dịch và tăng cường sức đề kháng, tạo tiền đề cho sự phát triển khỏe mạnh của bé.</p><p><img src="https://cdn.tgdd.vn/Products/Images/9079/229336/sua-bot-morinaga-so-2-chilmil-lon-320g-6-36-thang-tuoi-101123-052827.jpg"></p><h3><strong>Sữa bột Morinaga Chilmil cung cấp hàm lượng&nbsp;DHA và ARA&nbsp;thích hợp giúp mang lại cho bé nhiều lợi ích quan trọng</strong></h3><p>Trong giai đoạn đầu đời, việc bổ sung thêm DHA và ARA rất quan trọng đối với sự phát triển toàn diện của trẻ sơ sinh và trẻ nhỏ, giúp mang lại những tác động tích cực đến khả năng nhận thức, kết nối não bộ và miễn dịch ở trẻ.</p><p>Cụ thể, sự kết hợp giữa DHA và ARA giúp: Phát triển não bộ và hệ thần kinh trung ương; Phát triển nhận thức và hành vi; Phát triển chức năng thị giác và chức năng võng mạc; Tăng cường khả năng miễn dịch đối với các bệnh dị ứng và viêm da.</p><p><img src="https://cdn.tgdd.vn/Products/Images/9079/229336/sua-bot-morinaga-so-2-chilmil-lon-320g-6-36-thang-tuoi-hinh-bv-2.jpg"></p><h3><strong>Sữa bột bổ sung tiền lợi khuẩn bifidus hỗ trợ bé tiêu hóa tốt</strong></h3><p>Sữa Morinaga Chilmil có bổ sung 2 loại oligosaccharide là lactulose (duphalac) và raffinose giúp tăng cường hoạt động của các vi khuẩn có lợi như bifidobacteria, hỗ trợ tốt cho đường ruột của bé và ngăn ngừa nguy cơ táo bón.</p>', 8, 250000, 15000, 23, 13, 23, 1, N'2024-06-29 10:18:20.0000000', null, 2, N'2024-07-20 01:58:51.8449469', N'https://i.imgur.com/JNdd9dO.jpeg', 0x000000000000374C);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'61180DEF-9456-4BF4-A515-1F4C4D3E325D', N'Tên sản phẩm2.794089593574398', N'string', 1, 10000, 10000, 1, 1, 1, 0, N'2024-07-22 10:02:12.1782484', N'2024-07-22 19:39:43.6017980', 1, N'2024-07-22 12:39:43.6764580', N'https://placehold.co/200', 0x0000000000003963);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'89BB7676-C6BE-49C8-B6C2-1FA0D6691515', N'Sữa Nan Organic số 1 900gr cho bé từ 0-6 tháng tuổi', N'<p><em>"Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ"</em></p><h2><strong>Sữa bột Nan Organic số 1 900gr cho bé từ 0-6 tháng tuổi</strong></h2><p><strong>Sữa bột Nan&nbsp;Organic số 1 900gr</strong>&nbsp;là sản phẩm dinh dưỡng công thức hữu cơ dành cho trẻ từ 0 đến 6 tháng tuổi được chứng nhận hữu cơ của NASAA.&nbsp;<strong>NAN ORGANIC 1</strong>&nbsp;cung cấp cho trẻ các chất dinh dưỡng hỗ trợ cho sự phát triển khỏe mạnh về thể chất và trí não.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/SEO/Sua-cho-be/sua-nan-organic-so-1-900g.jpg">Sữa Nan Organic số 1 900g cho bé 0-6 tháng</em></p><h3><strong>Đặc điểm nổi bật của sữa&nbsp;bột Nan Organic số 1 900gr</strong></h3><ul><li><strong>Các thành phần* từ sữa:</strong>&nbsp;các thành phần của&nbsp;<strong>sữa&nbsp;bột Nan Organic</strong>&nbsp;số 1 900gr được sản xuất từ 100% sữa hữu cơ có nguồn gốc từ các trang trại bò sữa hữu cơ, tuân thủ các yêu cầu hữu cơ nghiêm ngặt nhất</li><li><br></li><li><strong>Đạm whey:</strong>&nbsp;Đạm có chất lượng giúp trẻ dễ tiêu hóa, dễ hấp thu để phát triển khỏe mạnh.</li><li><br></li><li><strong>DHA và ARA:</strong>&nbsp;Hỗ trợ phát triển trí não và thị lực NAN Organic 1 với các thành phần đáp ứng tiêu chuẩn hữu cơ khắt khe của NASAA, cơ quan chứng nhận hữu cơ của&nbsp;<a href="https://www.kidsplaza.vn/tag/sua-uc-cho-be" rel="noopener noreferrer" target="_blank">Úc</a>. Những thành phần có nguồn gốc từ những trang trại mà những con bò được tiếp cận với không khí trong lành và ăn các thức ăn hữu cơ.</li></ul><h3><strong>Độ tuổi sử dụng sữa bột Nan Organic số 1 900gr</strong></h3><p><strong>Sữa&nbsp;Nan Organic số 1 900gr</strong>&nbsp;là sản phẩm dinh dưỡng công thức hữu cơ dành cho trẻ từ 0 đến 6 tháng tuổi&nbsp;cung cấp cho trẻ các chất dinh dưỡng hỗ trợ cho sự phát triển khỏe mạnh về thể chất và trí não.</p><h3><strong>Hướng dẫn cách pha sữa bột Nan Organic số 1 900gr</strong></h3><ul><li>Rửa sạch tay trước khi pha&nbsp;sữa cho bé&nbsp;sơ sinh.</li><li><br></li><li>Rửa cốc và nắp đậy cho đến khi không còn bợn bẩn.</li><li><br></li><li>Đun sôi cốc và nắp đậy trong 5 phút. Đậy nắp kín cho đến khi sử dụng</li><li><br></li><li>Đun sôi nước trong 5 phút, để nguội bớt xuống khoảng 50℃</li><li><br></li><li>Tham khảo bảng hướng dẫn cách pha, rót chính xác lượng nước ấm cần dùng vào cốc đã được luộc.</li></ul><p><br></p>', 999, 609000, 0, 4, 4, 6, 1, N'2024-06-29 09:47:27.0000000', null, 1, N'2024-07-23 02:59:41.9760943', N'https://i.imgur.com/xvdfkPQ.jpeg', 0x00000000000039BF);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'A83DDEEB-E49C-4A5A-A7A1-29E5B1F87FFC', N'Sữa bầu Friso Mum Gold 900g hương cam', N'<h2><strong>Sữa bột Friso Gold Mum 900g hương cam thơm ngon dễ uống&nbsp;</strong></h2><p><strong>Sữa bột Friso&nbsp;Gold Mum 900g</strong>&nbsp;hương cam là thực phẩm thiết yếu,&nbsp;<strong>dễ uống</strong>&nbsp;cung cấp đầy đủ các dưỡng chất cần thiết cho mẹ&nbsp;trong quá trình&nbsp;<strong>mang thai</strong>&nbsp;và&nbsp;<strong>cho con bú</strong>,&nbsp;<strong>sữa bầu Friso Gold Mum</strong>&nbsp;rất tốt cho sự phát triển của thai nhi trong bụng mẹ.</p><p><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/do-cho-me/sua-bau/sua-bot-friso-gold-mum-900g-huong-cam-1.jpg"></p><p><em>Sữa bột Friso Gold Mum 900g hương cam</em></p><h3><strong>Thành phần sữa bầu Friso Gold Mum 900g</strong></h3><p>Bột sữa nguyên kem, Bột sữa gầy, Chất xơ (Inulin), Đường Sucrose, DHA, Magiê hydroxit cacbonat, Cholin bitartrat, Khoáng chất (Sắt pyrophotphat, Kẽm sunphat, Mangan sunphat, Natri selenit), Vitamin (vitamin A, vitamin D3, vitamin E, vitamin C, vitamin B1, vitamin B2, Niacin, vitamin B6, axít folic, axít pantothenic, vitamin B12 và vitamin K1), Hương Cam tổng hợp, Probiotic Bifidobacterium animalis subsp. lactis HN019 (**)</p><p>(**) chứa 14,600,000 cfu/100g tại thời điểm đóng gói.</p><p><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/do-cho-me/sua-bau/sua-bot-friso-gold-mum-900g-huong-cam-2.jpg"></p><p><em>Thành phần sữa bột Friso Gold Mum 900g hương cam</em></p><h3><strong>Đặc điểm nổi bật sữa Friso Gold Mum 900g</strong></h3><p><strong>&nbsp;Friso Gold Mum DualCare+TM</strong>&nbsp;được thiết kế để bổ sung vào bữa ăn hàng ngày của phụ nữ nhằm tối ưu hóa việc tiếp nhận dưỡng chất nhằm hỗ trợ nhu cầu dinh dưỡng cần thiết trong thời kỳ mang thai và&nbsp;cho con bú.&nbsp;<strong>Giúp mẹ khỏe mạnh</strong>&nbsp;từ bên trong để mẹ có thể&nbsp;<strong>thoải mái</strong>&nbsp;tận hưởng hành trình mang thai kì diệu.</p><p><strong>&nbsp;Friso Gold Mum Dualcare+</strong>&nbsp;bổ sung các vitamin và khoáng chất thiết yếu cho mẹ mang thai và cho con bú:</p><p><strong>- Vitamin B1, B3 &amp; B6</strong>&nbsp;tạo thuận lợi cho việc phóng thích năng lượng</p><p><strong>- Prebiotic và probiotic</strong>&nbsp;để&nbsp;<strong>hỗ trợ sức khỏe đường ruột</strong></p><p><strong>- Magiê</strong>&nbsp;để thư giãn</p><p><strong>- Choline</strong>&nbsp;là tiền chất của chất truyền dẫn thần kinh&nbsp;<strong>acetylcholine</strong>&nbsp;liên quan đến trí nhớ, hoạt động cơ bắp và các chức năng khác</p><p><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/do-cho-me/sua-bau/sua-bot-friso-gold-mum-900g-huong-cam-4.jpg"></p><p><em>Thành phần dinh dưỡng trung bình có trong sữa Friso Gold Mum 900g hương cam</em></p>', 998, 495000, 0, 14, 18, 1, 1, N'2024-07-11 01:30:42.8632952', null, 1, N'2024-07-23 03:00:37.7417739', N'https://i.imgur.com/8UXgcg9.jpeg', 0x00000000000039C0);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'34697F87-E573-4E85-8D32-2CE8AF9857AC', N'Sữa Enfagrow A2 Neuropro 4 1.7kg cho trẻ từ 3-6 tuổi', N'<p><strong><em>"Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ"</em></strong></p><h1>Sữa Enfagrow A2 Neuropro 4 1.7kg cho trẻ từ 3-6 tuổi</h1><p>Sữa Enfagrow A2 Neuropro 4 cung cấp các nhóm dưỡng chất thiết yếu để bé phát triển toàn diện. Sữa Enfagrow A2 Neuropro có vị thanh nhạt dễ uống, không chứa đường sucrose, phù hợp với hệ tiêu hóa còn non yếu của trẻ sơ sinh. Bên cạnh đó, sữa Enfagrow A2 số 4 giúp tăng cường lợi khuẩn trong đường ruột, giúp bé hạn chế gặp các vấn đề về hệ tiêu hóa.</p><h2>Xuất xứ và thương hiệu sữa Enfagrow A2 Neuropro 4</h2><p>Sữa Enfagrow A2 Neuropro 4 là sản phẩm thuộc thương hiệu Mead Johnson có nguồn gốc xuất xứ từ Thái Lan. Sữa Enfa được cung cấp rộng rãi tại thị trường các quốc gia Châu Á, trong đó có Việt Nam. </p><h2>Sữa Enfagrow A2 Neuropro 4 có những thành phần, công dụng gì?</h2><p>Đạm A2 beta-casein protein: sữa Enfagrow A2 Neuropro 4 là loại sữa chỉ chứa protein dạng A2 beta-casein được chọn lọc từ giống bò mang gene thuần cho ra sữa A2, trải qua quá trình chọn lọc nghiêm ngặt về mặt công nghệ di truyền.</p><p>MFGM: MFGM – Màng cầu béo là một thành phần giàu chất dinh dưỡng được tìm thấy trong sữa tự nhiên, cấu tạo gồm phức hợp trên 150 chất béo và protein của MFGM tác động tích cực trên cơ thể trẻ.</p><p>Phức hợp chất béo trong MFGM hỗ trợ cho sự phát triển của não, kết hợp bổ sung cùng DHA giúp tăng cường sự kết nối trên mỗi tế bào não. MFGM hỗ trợ phát triển nhận thức cũng như giúp điều chỉnh hành vi là một phần của sự phát triển thông minh cảm xúc (EQ) của trẻ.</p><p>&nbsp;Phức hợp protein có trong MFGM giúp hỗ trợ sự phát triển của hệ miễn dịch, giúp cơ chế kháng virut và kháng khuẩn, chống lại các bệnh nhiễm trùng. Điều này có nghĩa là MFGM giúp cơ chế miễn dịch của cơ thể khỏe mạnh, nhằm tăng cường khả năng chống lại việc nhiễm trùng.</p><p>DHA: DHA là một acid béo thuộc nhóm acid béo Omega-3 rất cần thiết cho sự phát triển trí não, thị giác của con người, giúp tăng khả năng miễn dịch và giảm nguy cơ phát triển dị ứng của trẻ.</p><p>ARA: Hoạt chất ARA hay còn gọi là AA là tên viết tắt của axit arachidonic, thuộc nhóm axit béo chưa bão hòa của Omega 6. Hoạt chất này trong sữa Enfagrow A2 Neuropro 4 giúp phát triển não bộ, võng mạc và có nhiều trong sữa mẹ, trứng gà.</p><p>PDX: PDX là tên viết tắt của Polydextrose, nguồn chất xơ hòa tan tự nhiên được chiết xuất từ thực vật, màu trắng, không mùi; giúp tiêu hóa và hấp thụ chất dinh dưỡng tốt hơn.</p><p>GOS: GOS trong sữa Enfagrow A2 Neuropro 4 là tên viết tắt của Galacto-oligosaccharides, là nguồn thức ăn cho lợi khuẩn trong đường ruột, giúp bảo vệ hệ tiêu hóa, giúp hấp thu dưỡng chất tốt hơn, giảm nguy cơ ung thư, tim mạch, có nhiều trong đậu nành, lúa mì, yến mạch nguyên cám, hành, tỏi, trái cây.</p><h2>sƯu điểm nổi bật của sữa Enfagrow A2 Neuropro 4</h2><p>Sữa Enfagrow A2 Neuropro 4 không đường sucrose, vị thanh nhạt dễ uống</p><p>Bộ đôi DHA và MFGM giúp trẻ phát triển nhận thức toàn diện cả về tư duy (IQ) và cảm xúc (EQ)</p><p>&nbsp;</p><p>Đạm quý A2 từ New Zealand giúp tăng hấp thu, tiêu hóa tốt</p><p>Chất xơ FOS trong sữa Enfagrow A2 Neuropro 4 giúp tăng lợi khuẩn và làm mềm phân</p><p>Sữa Enfagrow A2 Neuropro 3 hộp 1.7kg là sữa bột cho bé từ 3 đến 6 tuổi.</p><p>tring</p><h2>Thông tin sản phẩm Sữa Enfagrow A2 Neuropro 4 1.7kg</h2><p>Thương hiệu: Mead Johnson</p><p>Xuất xứ: Thái Lan</p><p>Độ tuổi sử dụng: 3-6 tuổi</p><p>Lượng nước đun sôi để nguội 40°C (ml): 188ml</p><p>Trọng lượng(Gram): 1.7kg</p>', 1000, 1285000, 0, 31, 2, 26, 1, N'2024-07-24 04:36:48.5086817', null, 1, N'2024-07-24 04:38:58.1509528', N'https://i.imgur.com/K6dkSXJ.jpeg', 0x0000000000003ADD);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'36CE021D-7A25-447F-9FA4-2F29AEF1174B', N'Sữa nước Pediasure hương vani 4x110ml (Thùng 12 lốc)', N'<h2><strong>Sữa Pediasure 110ml*4 hương vani cho trẻ từ 1-10 tuổi, tốt cho sức khỏe mỗi ngày</strong></h2><p><strong>Sữa công thức dạng nước&nbsp;Pediasure&nbsp;hương vani 4x110ml</strong>&nbsp;là&nbsp;<strong>hộp pha sẵn</strong>&nbsp;tiện lợi. Bổ sung dinh dưỡng đầy đủ và cân đối,&nbsp;<strong>vitamin, khoáng chất</strong>&nbsp;giúp phục hồi sức khỏe, tăng trưởng tốt. Công dụng chính của&nbsp;<strong><em>sữa Pediasure 110ml</em></strong>&nbsp;đã được chứng minh lâm sàng&nbsp;<strong>hỗ trợ bé</strong>&nbsp;từ 1 tuổi trở lên&nbsp;<strong>tăng cân khỏe mạnh</strong>, phát triển chiều cao tối ưu và tăng sức đề kháng cho bé trong vòng 9 tuần.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/sua-nuoc-pediasure-huong-vani-4x110ml-2.jpg"></em></p><p><em>Sữa Pediasure 110ml hương vani cho bé từ 1-10 tuổi</em></p>', 1, 1092000, 1032000, 17, 9, 13, 1, N'2024-06-19 11:44:19.0000000', null, 3, N'2024-07-23 03:56:01.0021849', N'https://i.imgur.com/zikh5ZA.jpeg', 0x0000000000003A17);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'573B4F1E-D75C-4D01-96A5-385885BE53AD', N'Sữa Nan Supreme Pro số 2 5-HMO 800g (6-24M)', N'<p><em>"Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ"</em></p><h2><strong>Sữa Nan Supreme Pro 2 5-HMO New 800g dành cho bé từ (6-24M)&nbsp;</strong></h2><p><a href="https://www.kidsplaza.vn/sua-nan.html" rel="noopener noreferrer" target="_blank"><strong>Sữa Nan</strong></a><strong>&nbsp;Supreme Pro&nbsp;2 5-HMO 800g (6-24M)</strong>&nbsp;là sản phẩm sữa công thức dành cho bé từ 6-24 tháng tuổi&nbsp;được điều chế từ dinh dưỡng công thức, bổ sung các dưỡng chất thiết yếu giúp trẻ tăng cường sức đề kháng, dễ tiêu hóa, dễ hấp thu và phòng ngừa nguy cơ dị ứng (chàm sữa).</p><p><img src="https://cdn-v2.kidsplaza.vn/media/product/NAN-supreme-2-800g1.jpg"></p><p><em>Sữa Nan Supreme Pro 2&nbsp;800g (6-24M)</em></p><h3><strong>Thành phần dinh dưỡng có trong sữa Nan Supreme Pro 2 800g:</strong></h3><p><img src="https://cdn-v2.kidsplaza.vn/media/product/sua-nan-supreme-so-3-5-hmo-800g-thuy-si-new-2-6y-0_1.jpg"></p><p><em>Bảng thành phần sữa Nan Supreme Pro 2 5HMO</em></p><h3><strong>Công thức dinh dưỡng sữa Nan Supreme Pro 2&nbsp;800g có chứa:</strong></h3><p>-&nbsp;<em>Sữa Nan Supreme Pro 2 800g</em>&nbsp;chứa phức hợp 5-HMO (2''FL, DFL, LNT, 3''SL, 6''SL): Công thức đầu tiên* bổ sung phức hợp 5 HMO giúp tăng cường sức đề kháng cho trẻ</p><p>- Chứa ĐẠM OPTIPRO HA: Đạm chất lượng Optipro thủy phân một phần (HA) giúp dễ tiêu hóa, hấp thu và phòng ngừa nguy cơ dị ứng (chàm sữa)**</p><p>-&nbsp;<a href="https://www.kidsplaza.vn/tag/sua-nan-supreme-pro-hmo" rel="noopener noreferrer" target="_blank"><strong>Sữa Nan Supreme</strong></a>&nbsp;pro số 2 5-HMO 800g<strong>&nbsp;c</strong>hứa Lợi khuẩn BIFIDUS BL hỗ trợ sức đề kháng ở trẻ</p><p><img src="https://cdn-v2.kidsplaza.vn/media/product/NAN-supreme-2-800g3.jpg"></p><p><em>Mặt sau bao bì&nbsp;Sữa Nan Supreme Pro 2 800g</em></p><p>- Thành phần<strong>&nbsp;DHA và ARA có trong&nbsp;</strong>sữa Nan Supreme Pro 2 800g: Hỗ trợ phát triển trí não và thị lực</p><p>-&nbsp;<a href="https://www.kidsplaza.vn/sua-bot-cho-be.html" rel="noopener noreferrer" target="_blank">Sữa công thức</a>&nbsp;<strong>Supreme Pro số 2&nbsp;800g</strong>&nbsp;5-HMO được hứng nhận an toàn khi bổ sung HMO cho trẻ bởi FDA và EFSA</p><p><strong>FDA:</strong>&nbsp;Cục Quản lý Thực phẩm &amp; Dược phẩm Hoa Kỳ</p><p><strong>EFSA</strong>: Cơ quan An Toàn Thực Phẩm Châu Âu</p><p>(*) Trong dòng sản phẩm Nestlé NAN</p><p>(**) nghĩa là giảm nguy cơ viêm da cơ địa, dị ứng với đạm có trong sữa bò</p>', 977, 635000, 625000, 21, 4, 1, 1, N'2024-06-24 10:57:11.0000000', null, 1, N'2024-07-23 05:32:05.7799654', N'https://i.imgur.com/xQweYBb.jpeg', 0x0000000000003A36);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'F2740C2A-5746-4ED5-ACE9-38CCE04E7AE1', N'Tên sản phẩm1.0837151880839846', N'string', 1, 10000, 10000, 1, 1, 1, 0, N'2024-07-23 01:45:56.5576023', N'2024-07-23 03:01:29.4614027', 1, N'2024-07-23 03:01:29.4628219', N'https://placehold.co/200', 0x00000000000039C2);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'374EA12C-B2DD-4CD2-A663-3EF0BDE03FAB', N'Sữa thanh Meiji EZcube 560g cho bé 1-3 tuổi', N'<p><em>*Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ*</em></p><p><strong><em>Sữa Meiji&nbsp;EZcube 560g cho bé 1-3 tuổi&nbsp;</em></strong>được sản xuất trên dây chuyên công nghệ tiên tiến hoàn toàn tự động, dưới sự quản lý vệ sinh và chất lượng chặt chẽ nên ba mẹ có thể hoàn toàn yên tâm khi bé yêu sử dụng dòng sữa bột này.&nbsp;Sữa mẹ là nguồn dinh dưỡng tốt nhất cho sự phát triển của trẻ sơ sinh và trẻ nhỏ, tuy nhiên đối với những trường hợp mẹ bị thiếu sữa hoặc sữa chưa về thì lúc việc bổ sung nguồn sữa bên ngoài là điểu rất cần thiết.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Meiji/sua-thanh-meiji-ezcube-560g-cho-be-1-3-tuoi-1b.jpg"></em></p><p><em>Sữa thanh Meiji EZcube 560g cho bé 1-3 tuổi</em></p><h3><strong>Đặc điểm nổi bật của sản phẩm sữa thanh Meiji EZcube 560g cho bé 1-3 tuổi</strong></h3><p>✓&nbsp;<strong>Sữa thanh Meiji</strong>&nbsp;EZcube 560g&nbsp;<strong>cung cấp nguồn dinh dưỡng và năng lượng</strong>: Với 400ml/ ngày cung cấp trên 100% nhu cầu dinh dưỡng khuyến nghị RNI của sắt, canxi, vitamin C, vitamin D và trên 70% nhu cầu vitamin và chất khoáng khác cho trẻ theo khuyến nghị của FAO/WHO, mang đến nguồn năng lượng và hệ dinh dưỡng cân bằng cho bé, tăng cường sức đề kháng để đảm bảo cho sự phát triển tối ưu .</p><p>✓&nbsp;<strong>Bổ sung Protein chất lượng, Phospholipids</strong>&nbsp;sữa chiết xuất từ sữa bò, chứa 1 lượng lớn sphingomyelin.</p><p>- Lactose là thành phần carbonhydrat chính trong sữa, mang tới nguồn năng lượng chính cho trẻ nhỏ, đồng thời tạo vị ngọt nhẹ cho sữa.</p><p>- Hơn 10 loại vitamin (vitamin A, C, D, K, E, các vitamin nhóm B), các loại vitamin cần thiết đối với trẻ nhỏm, mang đến hệ dinh dưỡng cân bằng, nâng cao hệ miễn dịch, cho một cơ thể khỏe mạnh để chống chọi với các loại bệnh thường gặp.</p>', 959, 405000, 305000, 7, 5, 15, 1, N'2024-06-22 17:51:39.0000000', null, 1, N'2024-07-24 08:51:46.6578403', N'https://i.imgur.com/3fpeRUF.jpeg', 0x0000000000003AE3);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'24A6E2E2-C996-4302-A8F6-3F9054CCE91C', N'Sữa nước Nutren Junior pha sẵn RTD 200ml', N'<p><em>“Sữa mẹ là thức ăn tốt nhất cho sức khoẻ và sự phát triển toàn diện của trẻ nhỏ”</em></p><h2><strong>Sữa nước pha sẵn Nutren Junior RTD&nbsp;dinh dưỡng y học 200ml</strong></h2><p>Nhẹ cân, thấp còi, suy dinh dưỡng là tình trạng cơ thể trẻ thiếu hụt dưỡng chất, năng lượng cần thiết trong chế độ ăn hàng ngày mà một trong những nguyên nhân phổ biến là do hấp thu dinh dưỡng kém.</p><p>Việc thiếu hụt dinh dưỡng còn có thể dẫn đến chậm tăng trưởng thể chất (trẻ có chiều cao, cân nặng thấp hơn so với bạn cùng trang lứa), đề kháng cũng suy giảm khiến trẻ dễ bệnh và thậm chí ảnh hưởng đến khả năng tư duy, khiến trẻ học kém.</p>', 983, 34000, 0, 17, 4, 20, 1, N'2024-06-24 11:26:27.0000000', null, 1, N'2024-07-23 03:03:22.1640892', N'https://i.imgur.com/LV6WGqa.jpeg', 0x00000000000039C5);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'7FFFE629-E853-43B7-B068-40F356854CB8', N'Sữa Similac 5G số 4 900g (cho bé 2-6 tuổi)', N'<h2><strong>Sữa Similac 5G số 4 900g dinh dưỡng (cho bé 2-6 tuổi)</strong></h2><p><strong>Sữa Similac&nbsp;5G số 4</strong>&nbsp;là sản phẩm dinh dưỡng cho bé từ 2-6 tuổi đến từ thương hiệu uy tín Abbott. Similac 5G số 4 sở hữu hệ dưỡng chất Prodi-GTM cùng nhiều dưỡng chất cần thiết&nbsp;khác để bé phát triển não bộ, tăng cường sức đề kháng và có được&nbsp;một hệ tiêu hóa khỏe mạnh.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Similac/sua-bot-similac-prodi-g-5hmo-so-4-900g-3.jpg"></em></p><p><em>&nbsp;&nbsp;Similac 5G số 4 900g dành cho bé từ 2 - 6 tuổi&nbsp;(Mẫu cũ)</em></p><h3><strong>Công dụng sữa Similac 5G số 4 900g&nbsp;</strong></h3><p><em>Sữa bột Similac số 4</em>&nbsp;là&nbsp;<strong>sữa cho bé 2 tuổi</strong>&nbsp;- 6 tuổi bị thiếu hoặc mất sữa mẹ. Hệ dưỡng chất Prodi-G có trong sữa Similac 5G giúp phát triển não bộ, tăng cường sức đề kháng và hệ tiêu hóa khỏe mạnh.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Similac/sua-bot-similac-5g-so-4-900g-cho-be-2-6-tuoi-a.jpg"></em></p><p><em>&nbsp;&nbsp;Similac 5G số 4 900g dành cho bé từ 2 - 6 tuổi (Mẫu mới)</em></p>', 1000, 519000, 0, 19, 1, 6, 1, N'2024-07-05 13:18:41.0000000', null, 1, N'2024-07-23 03:03:38.5467406', N'https://i.imgur.com/o5ilnGM.jpeg', 0x00000000000039C7);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'26665CC1-99B8-46EB-8BC0-41C5A9B86490', N'Sữa Nan Optipro HMO số 4 1.6kg cho trẻ 2-6 tuổi', N'<h2><strong>Sữa Nan Optipro HMO số 4 -&nbsp;sản phẩm dinh dưỡng công thức từ Thụy Sĩ</strong></h2><p>Với hơn 150 năm kinh nghiệm, Nestlé không ngừng tiên phong nghiên cứu &amp; sáng tạo trong lĩnh vực dinh dưỡng dành cho trẻ nhỏ. Ứng dụng những nghiên cứu tiên tiến của Nestlé cho sức khỏe lâu dài của trẻ, Nestlé NAN OPTIPRO tự hào là người bạn đồng hành đáng tin cậy cùng mẹ nuôi dưỡng tiềm năng cho các&nbsp;thiên tài nhỏ</p><p>- Sản phẩm dinh dưỡng công thức Nestlé® NAN® OPTIPRO® 4 1.6kg với công thức từ Thụy Sĩ, nhập khẩu chính hãng bởi Nestlé Việt Nam.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-nan/sua-nan-infinipro-so-4_1_.jpg">Sữa Nan Optipro HMO số 4 1.6kg (2-6 tuổi)</em></p><p><strong>Sữa&nbsp;Nan&nbsp;Nestle&nbsp;OptiproHMO số 4</strong>&nbsp;cải tiến mới, với sự xuất hiện của Nestlé HM-O 2''FL với hàm lượng thích hợp giúp tăng cường sức đề kháng, giảm ốm vặt cho trẻ. Bên cạnh đó, đạm chất lượng Optipro độc quyền từ Nestlé Thụy Sĩ với tỷ lệ đạm Whey vượt trội giúp dễ tiêu hóa, dễ hấp thu. Ngoài ra, sản phẩm còn chứa DHA và ARA, Omega 3, Omega 6 hỗ trợ tối ưu cho quá trình phát triển não bộ và thị lực của bé. Sữa bột cho bé&nbsp;<strong>Nan Optipro HMO số 4</strong>&nbsp;là sản phẩm dinh dưỡng công thức từ Thụy Sĩ, bổ sung các dưỡng chất thiết yếu giúp hỗ trợ tiêu hóa, tăng cường sức đề kháng của trẻ trong giai đoạn 2-6 tuổi.</p><h3><strong>Thành phần sữa&nbsp;Nan Optipro HMO số 4&nbsp;</strong></h3><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-nan/sua-nan-optipro-hmo-so-4-1-6kg-cho-tre-2-6-tuoi-2.jpg"></em></p><p><em>Thành phần sữa Nan Optipro HMO số 4&nbsp;</em></p><p><strong>Thành phần:</strong>&nbsp;Sữa&nbsp;bột tách kem (skimmed MILK), LACTOSE (từ SỮA),&nbsp;<strong>ĐẠM chất lượng OPTIPRO</strong>&nbsp;(ĐẠM WHEY-WHEY PROTEIN từ SỮA), Dầu hướng dương giàu Oleic, Dầu ĐẬU NÀNH (SOYA bean oil), Dầu dừa, Canxi Citrate, Natri Citrate, Chất nhũ hóa Lecithin ĐẬU NÀNH (SOYA lecithin), Glucose Syrup, Chất nhũ hóa monoglycerides, Kali Phosphate,&nbsp;<strong>2''-O-Fucosyllactose (2''- FL)</strong>, Dầu CÁ giàu DHA (FISH oil high DHA), Các Vitamin (C,Nicotinamide, E, B5, A, B1, B6, B2, Axit Folic, K1, Biotin, D3, B12), Maltodextrin, Natri clorid, Dầu nấm giàu ARA, Các khoáng chất (Sắt Sulfate, Kẽm sulfate, Đồng sulfate, Kali Iodide, Mangan Sulfate, Natri Selenate), Chất điều chỉnh độ axit axit Citric, Bifidobacterium lactis (Bifidus BL), Chất chống oxy hóa Ascorbyl Palmitate, Chất chống oxy hóa Tocopherol hỗn hợp.</p>', 996, 702000, 0, 19, 4, 4, 1, N'2024-06-24 10:32:51.0000000', null, 1, N'2024-07-23 03:04:13.2913305', N'https://i.imgur.com/eOoBlUA.jpeg', 0x00000000000039C8);
