INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'9D5E885B-D489-4950-97C1-4FB1571D06D4', N'Sữa Aptamil Úc Profutura số 3 900g cho bé 12M-36M', N'<h2><strong>Sữa Aptamil&nbsp;Úc số 3 900g cho bé 12M-36M hỗ trợ bé phát triển toàn diện</strong></h2><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Aptamil/sua-aptamil-profutura-uc-so-3-900g-cho-be-12m-36-1.jpg"></em></p><p><em>Sữa Aptamil Úc Profutura số 3 900g cho bé 12M-36M (Bao bì mới)</em></p><p><strong>Sữa Aptamil</strong>&nbsp;Úc số 3 Profutura 900g cho bé 12M-36M là dòng sữa công thức duy nhất cung cấp hầu hết những dưỡng chất có trong sữa mẹ như Vitamin và khoáng chất cần thiết là không thể thiếu. Đặc biệt,&nbsp;<strong>Aptamil Úc số 3</strong>&nbsp;là dòng sản phẩm thuộc phân khúc cao cấp chứa yếu tố sau mà không phải sữa nào cũng có: như men vi sinh Probiotic, dầu cá và chứa Metabolism.</p>', 958, 850000, 750000, 7, 3, 2, 1, N'2024-06-19 11:29:18.0000000', null, 1, N'2024-07-23 15:40:11.8730523', N'https://i.imgur.com/tOEluRK.jpeg', 0x0000000000003AB4);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'821C6787-A59D-4F0C-9528-52D22A7160FC', N'Sữa Nan Supreme Pro số 3 5-HMO 800g (2-6Y)', N'<p><em>"Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ"</em></p><h2><strong>Sữa Nan Supreme Pro 2 5-HMO New 800g dành cho bé từ (6-24M)&nbsp;</strong></h2><p><a href="https://www.kidsplaza.vn/sua-nan.html" rel="noopener noreferrer" target="_blank"><strong>Sữa Nan</strong></a><strong>&nbsp;Supreme Pro&nbsp;2 5-HMO 800g (6-24M)</strong>&nbsp;là sản phẩm sữa công thức dành cho bé từ 6-24 tháng tuổi&nbsp;được điều chế từ dinh dưỡng công thức, bổ sung các dưỡng chất thiết yếu giúp trẻ tăng cường sức đề kháng, dễ tiêu hóa, dễ hấp thu và phòng ngừa nguy cơ dị ứng (chàm sữa).</p><p><img src="https://cdn-v2.kidsplaza.vn/media/product/NAN-supreme-2-800g1.jpg"></p><p><em>Sữa Nan Supreme Pro 2&nbsp;800g (6-24M)</em></p><h3><strong>Thành phần dinh dưỡng có trong sữa Nan Supreme Pro 2 800g:</strong></h3><p><img src="https://cdn-v2.kidsplaza.vn/media/product/sua-nan-supreme-so-3-5-hmo-800g-thuy-si-new-2-6y-0_1.jpg"></p><p><em>Bảng thành phần sữa Nan Supreme Pro 2 5HMO</em></p><h3><strong>Công thức dinh dưỡng sữa Nan Supreme Pro 2&nbsp;800g có chứa:</strong></h3><p>-&nbsp;<em>Sữa Nan Supreme Pro 2 800g</em>&nbsp;chứa phức hợp 5-HMO (2''FL, DFL, LNT, 3''SL, 6''SL): Công thức đầu tiên* bổ sung phức hợp 5 HMO giúp tăng cường sức đề kháng cho trẻ</p><p>- Chứa ĐẠM OPTIPRO HA: Đạm chất lượng Optipro thủy phân một phần (HA) giúp dễ tiêu hóa, hấp thu và phòng ngừa nguy cơ dị ứng (chàm sữa)**</p><p>-&nbsp;<a href="https://www.kidsplaza.vn/tag/sua-nan-supreme-pro-hmo" rel="noopener noreferrer" target="_blank"><strong>Sữa Nan Supreme</strong></a>&nbsp;pro số 2 5-HMO 800g<strong>&nbsp;c</strong>hứa Lợi khuẩn BIFIDUS BL hỗ trợ sức đề kháng ở trẻ</p><p><img src="https://cdn-v2.kidsplaza.vn/media/product/NAN-supreme-2-800g3.jpg"></p><p><em>Mặt sau bao bì&nbsp;Sữa Nan Supreme Pro 2 800g</em></p><p>- Thành phần<strong>&nbsp;DHA và ARA có trong&nbsp;</strong>sữa Nan Supreme Pro 2 800g: Hỗ trợ phát triển trí não và thị lực</p><p>-&nbsp;<a href="https://www.kidsplaza.vn/sua-bot-cho-be.html" rel="noopener noreferrer" target="_blank">Sữa công thức</a>&nbsp;<strong>Supreme Pro số 2&nbsp;800g</strong>&nbsp;5-HMO được hứng nhận an toàn khi bổ sung HMO cho trẻ bởi FDA và EFSA</p><p><strong>FDA:</strong>&nbsp;Cục Quản lý Thực phẩm &amp; Dược phẩm Hoa Kỳ</p><p><strong>EFSA</strong>: Cơ quan An Toàn Thực Phẩm Châu Âu</p><p>(*) Trong dòng sản phẩm Nestlé NAN</p><p>(**) nghĩa là giảm nguy cơ viêm da cơ địa, dị ứng với đạm có trong sữa bò</p>', 995, 549000, 0, 19, 4, 1, 1, N'2024-06-22 18:23:40.0000000', null, 1, N'2024-07-04 02:51:30.0416665', N'https://i.imgur.com/lncChGz.jpeg', 0x000000000000371F);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'8F49BFD0-2ABC-438F-8540-56B99267661B', N'Sữa Frisolac Gold số 2 850g cho bé từ 6-12 tháng', N'<p><em>Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ</em></p><h2><strong>Sữa Frisolac Gold 2 850g cho bé từ 6-12 tháng</strong></h2><p><strong>Sữa Frisolac Gold 2 850g</strong>&nbsp;dành cho trẻ từ 6-12 tháng, cung cấp các dưỡng chất quan trọng để hỗ trợ hệ tiêu hóa và đường ruột của bé khỏe mạnh với Prebiotic(GOS). Ngoài ra, sữa Frisolac 2 cũng giúp cân bằng các dưỡng chất như DHA và AA cho sự phát triển não bộ, và chất chống oxy hóa như Vitamin A, Vitamin C và Vitamin E đối với sức khỏe miễn dịch.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/SEO/Sua-cho-be/sua-frisolac-gold-2-850g-6-12-thang.jpg">Sữa Frisolac Gold 2 850g cho bé 0-12 tháng mẫu mới</em></p><h3><strong>Ưu điểm vượt trội của sữa Frisolac Gold 2 850g</strong></h3><p><a href="https://www.kidsplaza.vn/tag/sua-frisolac-gold" rel="noopener noreferrer" target="_blank"><strong>Sữa Frisolac Gold</strong></a><strong>&nbsp;2 850g&nbsp;</strong>mới là sự kết hợp tối ưu giữa công nghệ&nbsp;<strong>LockNutri</strong>&nbsp;và dưỡng chất thiên nhiên hỗ trợ cho bé hệ miễn dịch và tiêu hóa khỏe mạnh.<em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/SEO/Sua-cho-be/sua-frisolac-gold-2-850g-6-den-12-thang.jpg"></em></p><p><em>Sữa Frisolac Gold 2 850g cho bé hệ miễn dịch và tiêu hóa khỏe mạnh</em></p><p><strong>Sữa Frisolac 2 -</strong>&nbsp;<strong>Dưỡng chất từ thiên nhiên:</strong></p><ul><li><strong>NOVAS Signature Milk</strong>&nbsp;- Nguồn sữa chất lượng tại trang trại Hà Lan của chúng tôi.</li><li><br></li><li><strong>Frisolac Gold số 2 850g&nbsp;</strong>được sản xuất bằng&nbsp;<strong>100% nguồn sữa từ giống bò sữa Friesian</strong>&nbsp;được chăn nuôi, chăm sóc bởi các gia đình nông dân Hà lan có hơn 145 năm kinh nghiệm.</li></ul>', 1000, 605000, 0, 5, 6, 3, 1, N'2024-07-04 12:42:11.0000000', null, 1, N'2024-07-20 15:54:43.9233442', N'https://i.imgur.com/pjCIKmT.jpeg', 0x00000000000038DC);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'E6767383-ED5F-47D7-BF21-56DE351563FC', N'Sữa Nan Supreme 1 400g cho bé 0-6M', N'<h2><strong>Sữa Nan Supremepro giàu dinh dưỡng 400g New cho bé từ 0 đến 6 tháng tuổi</strong></h2><p><strong>Sữa Nan&nbsp;Supreme&nbsp;1</strong>&nbsp;HMO 5 400g New từ 0 đến 6M là sản phẩm dinh dưỡng công thức từ Đức, bổ sung các dưỡng chất thiết yếu giúp trẻ tăng cường sức đề kháng, dễ tiêu hoá, dễ hấp thu và phòng ngừa nguy cơ dị ứng (chàm sữa).&nbsp;</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-nan/sua-nan-supreme-so-1-5-hmo-400g-new-0-6m-m.jpg"></em></p><p><em>Sữa Nan Supreme&nbsp;1 5HMO 400g New</em></p><h3><strong>Thành phần của sữa Nan Supreme số 1 5-HMO 400g New</strong></h3><p><strong>Thành phẩn có trong sữa Nan Supreme 1:</strong>&nbsp;</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-nan/sua-nan-supreme-so-1-5-hmo-400g-new-0-6m-k.jpg"></em></p><h3><strong>Công dụng&nbsp;của sữa Nan Supreme&nbsp;1 5-HMO 400g New:</strong></h3><p><strong>Với hơn 150 năm kinh nghiệm</strong>&nbsp;nghiên cứu và sáng tạo trong lĩnh vực dinh dưỡng cho trẻ, để đưa ra các sản phẩm bổ dưỡng phù hợp với các bé. Sản phẩm&nbsp;<strong>sữa Nan Supreme</strong>&nbsp;số 1 New hứa hẹn sẽ giúp bé phát triển một cách toàn diện nhất từ khi lọt lòng.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-nan/sua-nan-supreme-so-1-5-hmo-400g-new-0-6m-l.jpg"></em></p><p><strong>Sản phẩm sữa Nan Supreme&nbsp;1 400g New</strong>&nbsp;với công thức đầu tiên bổ sung 5 dưỡng chất<strong>&nbsp;(2’FL, DFL, LNT, 3’SL, 6’SL)</strong>&nbsp;giúp tăng cường sức đề kháng và giúp bé phát triển toàn diện.</p>', 997, 325000, 0, 4, 4, 7, 1, N'2024-06-24 11:19:49.0000000', null, 1, N'2024-07-23 03:05:58.2806273', N'https://i.imgur.com/mUtbV5m.jpeg', 0x00000000000039CB);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'FB9E905D-2BAC-4200-BFEC-5DD8038F050E', N'Sữa Frisolac Gold số 3 1400g cho bé từ 1-2 tuổi', N'<p><em>Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ</em></p><h2><strong>Sữa Frisolac Gold 3 1400g cho bé từ 1-2 tuổi công thức mới</strong></h2><p><strong>Sữa bột cho bé&nbsp;Frisolac Gold 3 1400g</strong>&nbsp;dành cho bé từ 1-2 tuổi cung cấp kẽm, sắt và nucleotides, tăng sức đề kháng tự nhiên cho cơ thể, nhờ vậy giúp bé luôn khỏe mạnh ngay từ bên trong để khám phá thế giới rộng lớn bên ngoài. Ngoài ra, sữa Frisolac Gold 3 cung cấp các dưỡng chất quan trọng hỗ trợ tăng trưởng và sự phát triển toàn diện của trẻ như Vitamin D, Taurin, Selen, DHA, Prebiotics, Probiotics và Canxi. Sản phẩm sữa Frisolac Gold 3 hoàn toàn không có chất bảo quản, chất tạo mùi nên bạn có thể yên tâm về chất lượng và tuyệt đối an toàn cho bé.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Frisolac/sua-bot-frisolac-gold-so-3-1400g-cho-be-tu-1-2-tuoi-5.jpg"></em></p><p><em>Sữa bột Frisolac Gold số 3 1400g cho bé từ 1-2 tuổi mẫu mới</em></p><h3><strong>Ưu điểm vượt trội của sữa Frisolac Gold 3 1400g</strong></h3><p><strong>Sữa Frisolac Gold&nbsp;3 1400g&nbsp;</strong>mới là sự kết hợp tối ưu giữa công nghệ&nbsp;<strong>LockNutri</strong>&nbsp;và dưỡng chất thiên nhiên hỗ trợ cho bé hệ miễn dịch và tiêu hóa khỏe mạnh.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Frisolac/sua-bot-frisolac-gold-so-3-1400g-cho-be-tu-1-2-tuoi-3.jpg"></em></p><p><em>Sữa bột Frisolac Gold 3 1400g - nguồn sữa chất lượng tại trang trại Hà Lan</em></p><p><strong>Sữa Frisolac Gold 3 dưỡng chất từ thiên nhiên:</strong></p><ul><li>Dòng sản phẩm sữa Frisolac Gold 3 chứa&nbsp;<strong>NOVAS Signature Milk</strong>&nbsp;- Nguồn sữa chất lượng tại trang trại Hà Lan của chúng tôi.</li><li><strong>Sữa Frisolac Gold số 3 1400g&nbsp;</strong>được sản xuất bằng&nbsp;<strong>100% nguồn sữa từ giống bò sữa Friesian</strong>&nbsp;được chăn nuôi, chăm sóc bởi các gia đình nông dân Hà lan có hơn 145 năm kinh nghiệm.</li></ul>', 1000, 845000, 0, 6, 6, 5, 1, N'2024-07-04 12:30:12.0000000', null, 1, N'2024-07-23 03:06:39.5811683', N'https://i.imgur.com/ZkdmORZ.jpeg', 0x00000000000039CC);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'EC1FBDA8-8DE0-4BD2-A73E-5E5C06956165', N'Sữa Meiji Growing Up Formula 800g nhập khẩu cho bé 1Y-3Y', N'<p><em>*Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ*</em></p><p><strong>Sữa&nbsp;</strong><a href="https://www.kidsplaza.vn/sua-bot-meiji-growing-up-formula-800g-cho-be-1y-3y.html" rel="noopener noreferrer" target="_blank"><strong>Meiji Growing Up Formula</strong></a>&nbsp;800g nhập khẩu chính hãng từ Nhật Bản, được kiểm duyệt thông tin kỹ càng trước khi cung cấp ra ngoài thị trường. Hiện nay, sản phẩm&nbsp;<em>sữa meiji số 9 nhập khẩu&nbsp;</em>là sự lựa chọn hàng đầu của các bố mẹ có con nhỏ muốn nâng cao trí tuệ và thể chất cho bé từ những tháng đầu đời.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Meiji/sua-bot-meiji-growing-up-formula-800g-cho-be-1y-3y-1a_1.jpg"></em></p><p><em>Sữa Meiji Growing Up Formula 800g&nbsp;</em></p><h2><strong>Thành phần và công dụng sữa Meiji Growing Up Formula</strong></h2><h3><strong>Công dụng của sữa Meiji Growing Up Formula</strong></h3><p><strong><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Meiji/sua-bot-meiji-growing-up-formula-800g-cho-be-1y-3y-1b_1.jpg"></em></strong></p><p><em>Sữa Meiji Growing Up Formula cho bé 1-3 tuổi phát triển toàn diện</em></p><p><strong><em>Meiji nhập khẩu 1-3&nbsp;hỗ trợ dinh dưỡng cho bé</em></strong></p><p><em>Với 400ml Sữa Meiji Growing Up Formula sẽ cung cấp trên 70% nhu cầu vitamin và chất khoáng cho trẻ 1-3 tuổi/ ngày theo khuyến nghị của FAO/WHO.</em></p><p><em>Trong 400ml&nbsp;</em><a href="https://www.kidsplaza.vn/tag/sua-meiji-nhap-khau" rel="noopener noreferrer" target="_blank"><strong>sữa meiji&nbsp;nhập khẩu chính hãng</strong></a>&nbsp;cung cấp 4,8mg sắt, chất đặc biệt quan trọng cho trẻ từ 1-3 tuổi. Ngoài ra tỷ lệ Canxi/Phospho là 2,0 và Canxi/Magie trong sữa Meiji là 7,6 theo đúng chuẩn FAO/WHO, đồng thời lượng vitamin D trong&nbsp;<em>sữa meiji nhập khẩu 1-3</em>&nbsp;cũng sẽ giúp bé hấp thu Canxi một cách tốt hơn giúp bé phát triển chiều cao một cách tối ưu.</p>', 974, 465000, 305000, 7, 5, 1, 1, N'2024-06-19 11:21:44.0000000', null, 1, N'2024-07-23 01:19:47.4888719', N'https://i.imgur.com/EtsC6vd.jpeg', 0x0000000000003981);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'3C940328-1278-47AE-BBAF-6263A30E3B2D', N'Tên sản phẩm6.176723396649337', N'string', 1, 10000, 10000, 1, 1, 1, 0, N'2024-07-19 05:46:22.3917794', N'2024-07-23 03:06:53.8387624', 1, N'2024-07-23 03:06:53.8402989', N'https://placehold.co/200', 0x00000000000039CD);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'F035F6E6-E308-45D6-8D92-655CCDCCBDF1', N'Sữa Vinamilk Yoko Gold 1 850g cho bé 0M-12M', N'<p><em>“Sữa mẹ là thức ăn tốt nhất cho sức khoẻ và sự phát triển toàn diện của trẻ nhỏ”</em></p><h2><strong>Sữa Vinamilk Yoko Gold số 1 hỗ trợ bé phát triển não bộ</strong></h2><p><strong>Sữa Yoko Gold</strong>&nbsp;Yoko Gold số 1 với công thức dinh dưỡng dễ tiêu hóa giúp trẻ hấp thu tối đa dưỡng chất thiết yếu cần thiết,&nbsp;tăng cường sức đề kháng và phát triển não bộ. Đây là sản phẩm được nhiều bà mẹ bỉm sữa tin tưởng lựa chọn và được bán chạy trên thị trường Việt Nam hiện nay. Với những ưu điểm vượt trội của mình, sữa bột Vinamilk Yoko Gold 1 chính là sự lựa chọn phù hợp nhất cho sự phát triển toàn diện của trẻ nhỏ.</p><p><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/SEO/Sua-cho-be/sua-vinamilk-yoko-1-850g-0-12-thang.jpg"></p><p><em>Sữa Vinamilk Yoko Gold 1 850g cho bé 0-12 tháng tuổi</em></p><h3><strong>Các công dụng nổi bật của sữa Vinamilk Yoko Gold 1</strong></h3><h4><strong>Giúp bé dễ hấp thu, tiêu hóa khỏe</strong></h4><ul><li>Chất xơ hòa tan GOS từ Nhật và FOS với tỷ lệ vàng 9:1</li><li><br></li><li>Kết hợp với Probiotics Bifidobacterium , BB-12TM</li><li><br></li><li>BB-12TM là thương hiệu của Chr. Hansen A/S</li></ul><p><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/SEO/Sua-cho-be/sua-vinamilk-yoko-gold-1-850g-0-12-thang.jpg"></p><p><em>Sữa Vinamilk Yoko Gold 1 850g đánh bay táo bón</em></p><h4><strong>Hỗ trợ phát triển não bộ</strong></h4><p>Trong sữa có chứa 100% DHA từ tảo đáp ứng hàm lượng theo khuyến nghị hằng ngày của các chuyên gia y tế Thế giới FAO/WHO. Sử dụng 2 ly sữa Vinamilk Yoko Gold 1 kết hợp với bữa ăn hàng ngày để giúp bé đạt hiệu quả tốt nhất (theo khuyến nghị hằng ngày của FAO/WHO cho trẻ từ 2 - 4 tuổi là 100 - 150 mg (DHA +EPA) và cho trẻ từ 4 - 6 tuổi là 150 - 200 mg *DHA + EPA).</p><p>Bên cạnh đó Taurine từ Nhật cùng Lutein và Choline có trong sữa hỗ trợ phát triển não bộ ở trẻ, giúp bé thông minh, học hỏi được nhiều điều thú vị từ sớm.</p><h4><strong>Hỗ trợ tăng cân, tăng sức đề kháng&nbsp;</strong></h4><p>Khi chọn&nbsp;<a href="https://www.kidsplaza.vn/sua-bot-cho-be.html" rel="noopener noreferrer" target="_blank">sữa bột</a>&nbsp;cho con nhiều bà mẹ luôn quan tâm đến công dụng tăng cân, tăng sức đề kháng của sữa. Trong sữa Yoko Gold 1 có chứa nhiều lợi khuẩn, khoáng chất giúp tăng cường hệ miễn cho bé, hạn chế ốm vặt, ốm do chuyển mùa, thay đổi thời tiết. Bên cạnh đó trong 100ml sữa Yoko Gold 1 cung cấp cho bé gân 300Kcal để bé có thật nhiều năng lượng hoạt động, vui chơi mỗi ngày.&nbsp;</p>', 1000, 479000, 0, 3, 10, 3, 1, N'2024-07-23 02:53:24.0860771', null, 1, N'2024-07-23 02:56:03.0452494', N'https://i.imgur.com/ccQqy1R.jpeg', 0x00000000000039BC);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'BDFE6F37-C81B-449F-BB7A-686228DFC045', N'Sữa nước Similac Eye-Q HMO hương vani 4x110ml (Thùng 12 lốc)', N'<h2><strong>Sữa nước Similac Eye-Q HMO hương vani 4x110ml cho bé trên 1 tuổi thơm ngon, an toàn</strong></h2><p><strong><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/SEO/Sua-cho-be/sua-nuoc-similac-eye-q-hmo-huong-vani.jpg"></em></strong></p><p><em>Sữa nước Similac Eye -Q HMO hương vani (Mẫu&nbsp;cũ)</em></p><p>Sữa nước cho bé&nbsp;<strong>Similac</strong>&nbsp;<strong>Eye-Q HMO hương vani 4x110ml</strong>&nbsp;là thực phẩm bổ sung của thương hiệu Abbott. Sản phẩm sữa Similac pha sẵn 110ml được chế biến từ những thành phần như: nước, sữa toàn phần, sữa tách kem, sucrose, lactose, khoáng chất (canxi, kali, sắt sunfat, kẽm), vitamin A, E, D3... dưới sự giám sát của Abbott Laboratories USA nên luôn có nguồn sữa sạch, an toàn từ khâu sản xuất đến khi đưa ra thị trường tiêu dùng.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Similac/sua-nuoc-similac-eye-q-hmo-huong-vani-4x110ml-a.jpg"></em></p><p><em>Sữa nước Similac Eye -Q HMO hương vani (Mẫu mới)</em></p><h3><strong>Thành phần có trong sữa nước Similac Eye-Q HMO hương vani 4x110ml&nbsp;</strong></h3><p>Nước, sữa toàn phần, sucrose, sữa tách kem, mật bắp, lactose,hỗn hợp inulin và fructo-oligosaccharid (FOS), KHOÁNG CHẤT (canxi carbonat, kali citrat, sắt sulfat, kẽm sulfat, mangan sulfat, đồng sulfat, natri selenat, kali iodid), cellulose gel. VITAMIN (natri ascorbat, acid ascorbic, cholin bitartrat, vitamin E acetat, niacinamid, vitamin D3, vitamin A acetat, thiamin hydroclorid,pyridoxin hydroclorid, canxi pantothenat, riboflavin, acid folic, vitamin K1, dbiotin, cyanocobalamin) hương vani tổng hợp , cellulose gum, carrageenan, lecithin đậu nành, gellan gum, taurin, acid docosahexaenoic (DHA) từ C. cohnii.</p>', 992, 696000, 646000, 11, 1, 13, 1, N'2024-07-05 13:11:09.0000000', null, 1, N'2024-07-20 15:44:24.5104713', N'https://i.imgur.com/iiyzrip.jpeg', 0x00000000000038D9);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'E21C39DB-D476-4F2A-9894-6863099A511F', N'Sữa Bầu Matilia Vị Dâu (Lốc 4 Hộp)', N'<h2><strong>Sữa bầu Matilia vị dâu (4 hộp) - Giải pháp dinh dưỡng hoàn hảo cho thai kỳ</strong></h2><p>Mang thai là giai đoạn quan trọng, ảnh hưởng trực tiếp tới thể chất cũng như trí tuệ của bé khi chào đời. Chính vì thế, mẹ cần có chế độ ăn uống hợp lý và khoa học để đảm bảo sức khỏe cũng như cung cấp chất dinh dưỡng cho bé phát triển khỏe mạnh.</p><p>Sữa bà bầu là sản phẩm được nhiều bà mẹ lựa chọn. Tuy nhiên, hương vị của các loại sữa này thường khá khó uống vì hàm lượng chất dinh dưỡng cao.</p><p>Đặc biệt, những mẹ bị ốm nghén khi mang thai, hay bị nôn ọe thì thường muốn bổ sung chất dinh dưỡng thiếu hụt từ khẩu phần ăn uống hàng ngày. Nhưng sữa bà bầu lại quá khó uống.</p><p><strong><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/do-cho-me/sua-bau/sua-bau-matilia-vi-dau-loc-4-hop.jpg"></strong></p><p><em>Sữa bầu pha sẵn Matilia vị dâu bổ sung dinh dưỡng thiếu hụt cho mẹ bầu</em></p><p><strong>Sữa&nbsp;bầu Matilia&nbsp;</strong>vị dâu&nbsp;là sản phẩm được hàng triệu bà mẹ tin dùng và yêu thích.</p><p>Ngoài đặc điểm nổi bật là thành phần dinh dưỡng khoa học thì mùi vị của sữa bầu matila&nbsp;cũng rất dễ uống. Sữa bầu Pháp&nbsp;giúp mẹ đỡ ốm nghén hơn, khỏe mạnh và linh hoạt hơn trong mọi hoạt động thường ngày.</p><h3><strong>Thành phần sữa Matilia cho mẹ bầu Vị Dâu (Lốc 4 Hộp)</strong></h3><p>Với thành phần chất dinh dưỡng dồi dào, bổ sung Axit Folic, vitamin B12, canxi, omega 3 (DHA/EPA), axit béo thiết yếu, vitamin D, magie, sắt...<strong>sữa bầu Pháp Matilia</strong>&nbsp;giúp mẹ bầu luôn khỏe mạnh, thai nhi phát triển toàn diện từ trong bụng mẹ.</p><ul><li>Protein</li><li>Glucid</li><li>DHA</li><li>EPA</li><li>Acidfolic (Vitamin B9)</li><li>Vitamin D</li><li>Sắt</li><li>Iot</li><li>Canxi</li></ul><h3><strong>Công dụng&nbsp;nổi bật của sữa Bầu Matilia Vị Dâu (Lốc 4 Hộp)</strong></h3><ul><li><strong>Sữa bà bầu Matilia</strong>&nbsp;cung cấp hà lượng lớn Axit Folic, vitamin B12, Canxi, Omega 3 (DHA/ EPA), axit béo thiết yếu,Vitamin D, Magie, sắt… Đây là những dưỡng chất vô cùng cần thiết và quan trọng với cả mẹ và bé trong thai kỳ.</li><li>Sản phẩm&nbsp;sữa bầu Matilia chính hãng&nbsp;được lên men tự nhiên theo công nghệ UHT tiên tiến, đảm bảo sản hẩm hoàn toàn được tiệt trùng.</li><li>Vị dâu tây tự nhiên, giúp mẹ dễ uống hơn, không có cảm giác bị ngấy hay ghê cổ như nhiều sản phẩm thông thường khác.</li><li>Thành phần&nbsp;sữa Matilia không sử dụng chất bảo quản hay bất cứ chất hóa học độc hại nào, vô cùng an toàn với mẹ và bé khi sử dụng.</li><li>Thiết kế hộp nhỏ 200ml, rất tiện lợi khi sử dụng. Dễ dàng mang theo khi đi làm, đi học hay đi chơi.</li></ul>', 0, 100000, 80000, 15, 14, 1, 1, N'2024-07-19 06:08:41.0126635', null, 2, N'2024-07-23 13:41:58.2958187', N'https://i.imgur.com/k4n5ual.jpeg', 0x0000000000003A9C);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'E16F603A-E34D-4025-8C2E-6E4F06A21598', N'Combo 4 hộp sữa Aptamil Profutura KID Cesarbiotik số 3 800g (2Y+)', N'<h2><strong>Sữa Aptamil Profutura KID Cesarbiotik số 3 800g (2Y+) cung ấp dinh dưỡng đầy đủ cho sự phát triển toàn diện của trẻ</strong></h2><p><strong>APTAMIL KID</strong>&nbsp;mang đến diện mạo mới cho Aptakid (được trình làng qua bao bì mới của Aptakid New Zealand số 3). Sản phẩm này hoàn toàn chứa trọn vẹn dưỡng chất&nbsp;<strong>SYNBIOTIC Độc quyền</strong>, đặc biệt phù hợp cho trẻ sinh mổ. Được sự tin dùng của&nbsp;82% bà mẹ sinh mổ, Aptakid tự hào là sự lựa chọn dinh dưỡng khoa học, cung cấp đầy đủ dưỡng chất giúp tăng cường đề kháng và sức khỏe mạnh mẽ cho trẻ sinh mổ.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Aptamil/sua-aptamil-profutuna-kid-cesarbiotik-so-3-800g-2y-5.jpg"></em></p><p>Diện mạo mới sữa Aptamil Profutura KID Cesarbiotik số 3 800g (2Y+)</p><h3><strong>Thành phần sữa Aptamil Profutura KID Cesarbiotik số 3 800g (2Y+)</strong></h3><p>Gồm: Lactose (sữa bò), Sữa tách béo (sữa bò), Kem sữa (sữa bò), Galacto- oligosaccharides (GOS) (sữa bò), Acid decosahexaenoic (DHA) (Dầu cá), Fructo- oligosaccharides chuỗi dài (IcFOS) (rễ rau diếp xoăn), Maltodextrin (ngô), Các khoáng chất (Calci carbonat, Mangan sulfat, Sắt (II) sulfat, Kẽm sulfat, Kali iodid), Các vitamin (Vitamin E (DL-alpha-tocopheryl acetat), Vitamin C (Natri-L-ascorbat), Vitamin B3 (Nicotinamid), Vitamin B2 (Riboflavin), Vitamin A (Retinyl acetat), Vitamin D3 (Cholecalciferol), Acid folic (Acid pteroymonoglutamic), Vitamin B6 (Pyridoxin hydroclorid), Vitamin B1 (Thiamin hydroclorid)), Chất nhũ hóa (lecithin đậu nành, INS 322(i)), Bifidobacterium Breve M-16V, Chất chống oxy hóa (Tocopherol concentrate (dạng hỗn hợp) (INS 307b), Ascorbyl palmitat (INS 304), dl-alpha-Tocopherol (INS 307c)).</p><p>Thông tin về dị ứng thực phẩm: Có chứa sữa, dầu cá, đậu nành.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Aptamil/sua-aptamil-profutuna-kid-cesarbiotik-so-3-800g-2y-1.jpg"></em></p><h3><strong>Lợi ích dinh dưỡng cho trẻ sinh mổ khi sử dụng sữa Profutura KID Cesarbiotik số 3</strong></h3><p>Lấy cảm hứng từ những năm tháng đầu đời diệu kỳ, và trên hết là hành trình lớn khôn theo cách rất riêng của trẻ, chúng tôi luôn thấu hiểu mong muốn con mình luôn khỏe mạnh và sẵn sàng cùng bố mẹ xây dựng đề kháng vững vàng cho con, dù con sinh thường hay sinh mổ.</p><p>Chúng tôi tâm huyết nghiên cứu những dưỡng chất phù hợp với trẻ sinh mổ: SYNBIOTIC độc quyền được chứng minh hiệu quả, giúp tăng cường đề kháng cho trẻ sinh mổ.</p>', 995, 2764000, 2484000, 8, 3, 12, 1, N'2024-06-19 11:32:50.0000000', null, 1, N'2024-07-23 03:07:54.2146624', N'https://i.imgur.com/j7cSjft.jpeg', 0x00000000000039CE);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'A299F84C-DD24-4340-A544-70C251A542CB', N'Sữa Meiji Infant Formula 800g nhập khẩu cho bé 0-1Y', N'<p><em>*Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ*</em></p><p><strong>Sữa&nbsp;Meiji&nbsp;</strong>Infant Formula được sản xuất theo nghiên cứu dành cho trẻ em Việt Nam trên dây chuyền hiện đại của Nhật Bản, hoàn toàn tự động, đạt tiểu chuẩn ISO 9001. Cung cấp đầy đủ dưỡng chất, vitamin, khoáng chất cần thiết giúp trẻ phát triển toàn diện nhất.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Meiji/sua-bot-meiji-infant-formula-800g-nhap-khau-cho-be-0-1y-1a.jpg"></em></p><p><em>Sữa bột Meiji Infant Formula 800g&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</em></p><h2><strong>Thành phần và công dụng của sữa Meiji Infant Formula</strong></h2><h3><strong>Công dụng của sữa Meiji Infant Formula</strong></h3><p><strong><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Meiji/sua-bot-meiji-infant-formula-800g-nhap-khau-cho-be-0-1y-1b.jpg"></em></strong></p><p><em>Sữa Meiji Infant Formula 800g cho bé sự phát triển toàn diện</em></p><p><strong>Bổ sung Nucleotide</strong></p><p><em>Bổ sung 5 loại Nucleotide để có hàm lượng Nucleotide gần nhất với sữa mẹ ( Axit adenylic, Axit cytidylic, Axit inosinic, Axit guanylic, Axit uridylic ). Phần chính của β-lactoglobulin không tồn tại trong sữa mẹ được phân hủy</em></p><p><strong>Bổ sung Taurine</strong></p><p><em>Trẻ em không có khả năng tự tổng hợp Taurine từ Methiomin như người lớn mà được cung cấp Taurin qua sữa mẹ.&nbsp;</em><strong>Sữa Meiji Infant Formula</strong>&nbsp;cung cấp Taurine giúp bé phát triển võng mạc và thị giác.</p><p><strong>Bổ sung chất béo</strong></p><p><em>Bổ sung docosahexaenoic acid (DHA) và arachidonic acid (ARA): Nồng độ DHA được điều chỉnh đến 20mg/100Kaclo, nằm trong nồng độ DHA có trong sữa mẹ Nồng độ ARA được điều chỉnh đến 20mg/100Kcalo, nằm trong phạm vi có trong sữa mẹ</em></p><p><em>Tăng cường axit palmitic gắn kết với Triglycerid tại vị trí β: nồng độ được điều chỉnh tới 1010 mg/100 Kcalo, nằm trong phạm vi SM ( 787 -1474 mg/100 Kcalo ). Nồng độ axit palmitic gắn kết Triglycerid tại vị trí β tăng đến 490 mg/100 kcalo (giúp trẻ hấp thu và sử dụng axit béo này 1 cách hiệu quả), nồng độ axit palmitic gắn với triglycerid tại vị trí α hoặc α’ được giảm xuống còn khoảng 520 mg/100 Kcalo</em></p><p><em>Bổ sung Cholesterol (thành phần chính của muối mật- giúp tiêu hóa chất béo): ở trẻ nhỏ, khả năng tổng hợp cholesterol thấp, không đủ cho nhu cầu, do đó nó được cung cấp qua sữa mẹ (nồng độ 14,0 – 19,9 mg/100 Kcalo). Trong đó,&nbsp;</em><strong>sữa meiji nhập khẩu</strong>&nbsp;Formula đạt 14,6 mg/100 Kcalo</p>', 1000, 529000, 0, 3, 5, 1, 1, N'2024-06-19 11:20:43.0000000', null, 1, N'2024-07-23 03:08:39.2211944', N'https://i.imgur.com/N8fAvXl.jpeg', 0x00000000000039CF);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'31210490-11C5-42CF-93AF-7C41F146634E', N'Tên sản phẩm1.1566381391827374', N'string', 1, 10000, 10000, 1, 1, 1, 0, N'2024-07-13 08:34:43.8514852', N'2024-07-23 03:10:56.4402020', 1, N'2024-07-23 03:10:56.4419039', N'https://placehold.co/200', 0x00000000000039D5);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'F2900267-0521-44EF-90FF-7C54090AA88F', N'Sữa bầu Morinaga vị Cafe Nhật (216g)', N'<h2><strong>Sữa&nbsp;bầu Morinaga vị Cafe Nhật 216g bổ sung các dưỡng chất cần thiết cho mẹ&nbsp;</strong></h2><p>Bên cạnh nguồn dinh dưỡng từ những bữa ăn hàng ngày, mẹ cần bổ sung sữa bột hằng ngày để thai nhi có thê hấp thụ đầy đủ dưỡng chất ngay từ khi còn trong bụng mẹ. Mẹ bầu có 1 sức khỏe tốt thì còn yêu sinh ra mới khỏe mạnh, thông minh. Với nguồn nguyên liệu sạch, công nghệ hiện đại,&nbsp;<strong>sữa&nbsp;bầu&nbsp;Morinaga&nbsp;vị Cafe</strong>&nbsp;sẽ cung cấp đầy đủ dinh dưỡng cần thiết cho mẹ mang thai và cho con bú.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/morinaga/sua-ba-bau-morinaga-vi-cafe-216g-01.jpg"></em></p><p><em>Sản phẩm sữa bầu Morinaga vị cafe chất lượng từ đất nuốc Nhật Bản</em></p><h3><strong>Công dụng nổi bật của sản phẩm sữa bầu Morinaga vị cafe 216g</strong></h3><ul><li><strong>Sữa bầu Morinaga</strong>&nbsp;cung cấp đầy đủ&nbsp;<strong>12 loại vitamin</strong>&nbsp;cần thiết như A,B1,B2,B6,B12,C,D….&nbsp;và dinh dưỡng cân bằng tốt cho mẹ và cho bé trong thời kỳ phát triển thai nhi như : Sắt, DHA, Canxi, Maje, axit folic, lipit…..</li><li><br></li><li>Sự nổi bật nhất của&nbsp;sữa bầu của Nhật&nbsp;Morinaga đó là hàm lượng dinh dưỡng trong sữa tập trung vào bé là chính, vậy nên sẽ giúp các bà bầu không tăng cân quá nhiều mà thai nhi đủ chất và phát triển khỏe mạnh. Từ đó mẹ nhanh chóng lấy lại vóc dáng sau khi sinh con.</li><li><br></li><li><strong>Sữa bầu Nhật Morinaga&nbsp;</strong>vị Cafe bổ sung lượng lớn&nbsp;<strong>chất xơ</strong>&nbsp;là một thành phần quan trọng giúp phát triển hệ vi sinh đường ruột của mẹ và bé, hạn chế tình trạng táp bón hay xảy ra ở mẹ bầu.</li></ul><p><br></p>', 992, 225000, 205000, 15, 13, 18, 1, N'2024-06-22 19:13:13.0000000', null, 1, N'2024-07-23 03:09:12.3560203', N'https://i.imgur.com/kRXKsxG.jpeg', 0x00000000000039D0);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'508E6280-992A-4384-98AC-7D905E89C2C5', N'Thùng sữa nước Nan Grow 4*180ml cho trẻ từ 12 tháng (1 thùng 6 lốc)', N'<h2><strong>Sữa nước Nan Grow 4*180ml cho trẻ từ 12 tháng thơm ngon, dinh dưỡng cho bé</strong></h2><p><strong>Sữa Nan Grow</strong>&nbsp;pha sẵn 180ml (Lốc 4 hộp) chứa hàm lượng&nbsp;<strong>Canxi và Vitamin D3</strong>&nbsp;cao, được sản xuất theo công thức tiên tiến của Nestle Thụy Sĩ giúp bé cao lớn, khỏe mạnh. Ngoài ra, sản phẩm còn bổ sung nhiều dưỡng chất cần thiết khác, trong đó có&nbsp;<strong>Omega 3</strong>&nbsp;đóng vai trò quan trọng đối với sự phát triển trí não, thị lực của con yêu. Nhờ thiết kế pha sẵn tiện lợi, ba mẹ có thể dễ dàng bổ sung dinh dưỡng cho trẻ từ 1-3 tuổi theo khuyến nghị 2 hộp mỗi ngày.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/sua-nan/sua-nuoc-nan-grow-4-180ml-cho-tre-tu-12-thang-1.jpg"></em></p><p><em>Sữa nước Nan Grow 4*180ml cho trẻ từ 12 tháng</em></p><h3><strong>Thành phần của sản phẩm sữa nước Nan Grow&nbsp;cho trẻ từ 12 tháng</strong></h3><p>Sữa dinh dưỡng pha sẵn Nan Grow 180ml (Lốc 4 hộp) có thành phần gồm: Sữa (milk) 84% (nước, sữa bột - milk powder, chất béo sữa - milk fat), nước, hỗn hợp dầu thực vật - có chứa đậu nành (contain soya) (dầu hạt cải có hàm lượng axit erucic thấp, dầu hướng dương có hàm lượng axit oleic cao), đường lactose từ sữa (from milk), chất xơ hòa tan oligofructose, chất ổn định (460(i), 332(ii), 500(ii), 466, 407), các khoáng chất (calci carbonat, dicalci phosphat, sắt sulphat, kẽm sulfat, kali iodid), chất nhũ hóa lecithin - chiết xuất từ đậu nành (soya lecithin), các vitamin (C, E, niacin, axit pantothenic, B1, B6, A, axit folic, K1, biotin, D3), 2’-0-Fucosyllactose (2’-FL) từ sữa (from milk) và hương liệu tổng hợp.</p>', 989, 414000, 404000, 11, 4, 17, 1, N'2024-06-22 18:12:02.0000000', null, 1, N'2024-07-23 03:09:43.2330331', N'https://i.imgur.com/O5IMidj.jpeg', 0x00000000000039D1);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'3007E8A8-9069-4367-A23B-7EC9A3AF217C', N'Sữa Meiji thanh số 9 nội địa Nhật 672g cho bé 1Y-3Y', N'<p><em>*Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ*</em></p><h2><strong>Sữa Meiji thanh số 9 cùng bé lớn khôn mỗi ngày</strong></h2><p><strong>Sữa Meiji thanh&nbsp;số 9</strong>&nbsp;Nhật Bản được thiết kế dạng thanh cô đặc, thuận tiện cho bạn pha sữa mọi lúc, mọi nơi mà không lỉnh kỉnh khi phải mang cả hộp sữa to. Đặc biệt&nbsp;<a href="https://www.kidsplaza.vn/tag/sua-meiji-thanh" rel="noopener noreferrer" target="_blank"><strong>sữa thanh meiji</strong></a>&nbsp;số 9 thích hợp khi mang theo trong túi đựng đồ, mang đi khám bệnh, du lịch, đi chơi<strong>...</strong></p><h3><strong>Thành phần và đặc điểm sữa Meiji thanh&nbsp;số 9</strong></h3><h4><strong>Các thành phần chính có trong sữa Meiji thanh số 9</strong></h4><p>Sữa Meiji thanh số 9 nội địa Nhật có khả năng cung cấp tới hơn 70% nhu cầu vitamin và chất khoáng cho trẻ 1 - 3 tuổi/ngày theo khuyến nghị của FAO/WHO. Trong thành phần&nbsp;<strong>sữa Meiji thanh số 9</strong>&nbsp;bao gồm đầy đủ các vitamin (A, C, D, E, K, nhóm B,...) và khoáng chất mang đến cho bé một cơ thể mạnh khỏe, tràn đầy năng lượng.</p><p><strong>Sữa Meiji&nbsp;Nhật</strong>&nbsp;cung cấp chất lượng Protein tốt (gồm 40% Whey protein) và tăng tổng lượng lưu huỳnh chứa axit amin như Cysteine.</p><p>400 ml chứa 10,1g chất béo.&nbsp;<em>Sữa meiji thanh 1-3 nội địa</em>&nbsp;bổ sung Phospholipids sữa chiết xuất từ sữa bò, chứa 1 lượng lớn sphingomyelin.</p><p>Lactose là thành phần carbonhydrat chính trong sữa Meiji. Chất này được tìm thấy rất nhiều trong sữa mẹ mang tới vị ngọt nhẹ cho sữa, cung cấp nguồn năng lượng chính cho trẻ nhỏ.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/product/suabotchobe/Meiji/sua-thanh-meiji-so-9-noi-dia-nhat-672g-cho-be-1y-3y-1.jpg"></em></p><p><em>Sữa Meiji thanh số 9 được các mẹ tin dùng cho bé</em></p><h4><strong>Đặc điểm nổi bật của sữa Meiji thanh số 9&nbsp;</strong></h4><ul><li><strong>Sữa Meiji nội địa thanh</strong>&nbsp;số 9 sử dụng công nghệ tiên tiến của Nhật Bản mang đến những viên sữa bột hình lập phương (1 viên pha được 40ml) dễ hòa tan, giúp mẹ thuận tiện hơn trong việc pha sữa bởi mẹ đã không cần phải cân nhắc đong đếm lượng&nbsp;sữa bột&nbsp;khi pha sữa cho bé. Điều này cũng vô cùng tiện lợi để mẹ mang sữa Meiji thanh theo cho bé ăn khi cả nhà ra ngoài, đồng thời dễ dàng hơn trong việc kiểm soát lượng sữa bé đã dùng hay còn dư trong hộp.&nbsp;</li><li>Sữa Meiji thanh số 9 hộp 672g bổ sung đầy đủ các loại vitamin và khoáng chất thiết yếu cho bé phát triển toàn diện về thể chất và trí tuệ như: canxi, vitamin D,... giúp phát triển chiều cao; DHA có trong&nbsp;<em>sữa meiji thanh 1-3 nội địa</em>&nbsp;giúp phát triển trí não và tăng cường thị lực; chất xơ FOS hỗ trợ hệ tiêu hóa; Nucleotide trong sữa mẹ giúp tăng cường hệ miễn dịch, sắt giúp phòng chống nguy cơ thiếu máu do thiếu sắt,...</li><li><br></li><li>Thành phần FOS (Fructo-oligosaccha ride) có trong sữa Meiji thanh số 9 là chất xơ hòa tan giúp trẻ có một hệ tiêu hóa khỏe mạnh khiến trẻ ăn ngon miệng hơn, nhanh chóng tăng cân.</li></ul><p><br></p>', 988, 499000, 0, 7, 5, 11, 1, N'2024-06-19 11:29:54.0000000', null, 1, N'2024-07-23 03:10:25.8843449', N'https://i.imgur.com/SNkCHpU.jpeg', 0x00000000000039D2);
