INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'E60FE852-3C6A-4920-80A4-864A069BFEAA', N'Sữa Nan Optipro Plus số 4 5HMO 800g cho bé 2-6 tuổi', N'<p><em>"Sữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ"</em></p><h2><strong>Sữa Nan Supreme Pro 2 5-HMO New 800g dành cho bé từ (6-24M)&nbsp;</strong></h2><p><a href="https://www.kidsplaza.vn/sua-nan.html" rel="noopener noreferrer" target="_blank"><strong>Sữa Nan</strong></a><strong>&nbsp;Supreme Pro&nbsp;2 5-HMO 800g (6-24M)</strong>&nbsp;là sản phẩm sữa công thức dành cho bé từ 6-24 tháng tuổi&nbsp;được điều chế từ dinh dưỡng công thức, bổ sung các dưỡng chất thiết yếu giúp trẻ tăng cường sức đề kháng, dễ tiêu hóa, dễ hấp thu và phòng ngừa nguy cơ dị ứng (chàm sữa).</p><p><img src="https://cdn-v2.kidsplaza.vn/media/product/NAN-supreme-2-800g1.jpg"></p><p><em>Sữa Nan Supreme Pro 2&nbsp;800g (6-24M)</em></p><h3><strong>Thành phần dinh dưỡng có trong sữa Nan Supreme Pro 2 800g:</strong></h3><p><img src="https://cdn-v2.kidsplaza.vn/media/product/sua-nan-supreme-so-3-5-hmo-800g-thuy-si-new-2-6y-0_1.jpg"></p><p><em>Bảng thành phần sữa Nan Supreme Pro 2 5HMO</em></p><h3><strong>Công thức dinh dưỡng sữa Nan Supreme Pro 2&nbsp;800g có chứa:</strong></h3><p>-&nbsp;<em>Sữa Nan Supreme Pro 2 800g</em>&nbsp;chứa phức hợp 5-HMO (2''FL, DFL, LNT, 3''SL, 6''SL): Công thức đầu tiên* bổ sung phức hợp 5 HMO giúp tăng cường sức đề kháng cho trẻ</p><p>- Chứa ĐẠM OPTIPRO HA: Đạm chất lượng Optipro thủy phân một phần (HA) giúp dễ tiêu hóa, hấp thu và phòng ngừa nguy cơ dị ứng (chàm sữa)**</p><p>-&nbsp;<a href="https://www.kidsplaza.vn/tag/sua-nan-supreme-pro-hmo" rel="noopener noreferrer" target="_blank"><strong>Sữa Nan Supreme</strong></a>&nbsp;pro số 2 5-HMO 800g<strong>&nbsp;c</strong>hứa Lợi khuẩn BIFIDUS BL hỗ trợ sức đề kháng ở trẻ</p><p><img src="https://cdn-v2.kidsplaza.vn/media/product/NAN-supreme-2-800g3.jpg"></p><p><em>Mặt sau bao bì&nbsp;Sữa Nan Supreme Pro 2 800g</em></p><p>- Thành phần<strong>&nbsp;DHA và ARA có trong&nbsp;</strong>sữa Nan Supreme Pro 2 800g: Hỗ trợ phát triển trí não và thị lực</p><p>-&nbsp;<a href="https://www.kidsplaza.vn/sua-bot-cho-be.html" rel="noopener noreferrer" target="_blank">Sữa công thức</a>&nbsp;<strong>Supreme Pro số 2&nbsp;800g</strong>&nbsp;5-HMO được hứng nhận an toàn khi bổ sung HMO cho trẻ bởi FDA và EFSA</p><p><strong>FDA:</strong>&nbsp;Cục Quản lý Thực phẩm &amp; Dược phẩm Hoa Kỳ</p><p><strong>EFSA</strong>: Cơ quan An Toàn Thực Phẩm Châu Âu</p><p>(*) Trong dòng sản phẩm Nestlé NAN</p><p>(**) nghĩa là giảm nguy cơ viêm da cơ địa, dị ứng với đạm có trong sữa bò</p>', 1000, 455000, 0, 19, 4, 1, 1, N'2024-06-22 18:06:25.0000000', null, 1, null, N'https://i.imgur.com/moJdEEC.jpeg', 0x000000000000372D);
