INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'278A3FEB-0A9C-4346-A59B-DFB27F1B274A', N'Sữa Frisolac Gold số 3 850g cho bé từ 1-2 tuổi', N'<p><em>ữa mẹ là thức ăn tốt nhất cho sức khỏe và sự phát triển toàn diện của trẻ nhỏ</em></p><h2><strong>Sữa bột Frisolac Gold 3 -&nbsp;hỗ trợ tăng trưởng và sự phát triển toàn diện của trẻ</strong></h2><p><strong>Sữa Frisolac Gold 3 850g</strong>&nbsp;là loại&nbsp;sữa bột cho bé&nbsp;từ 1-2 tuổi cung cấp kẽm, sắt và nucleotides, tăng sức đề kháng tự nhiên cho cơ thể, nhờ vậy giúp bé luôn khỏe mạnh ngay từ bên trong để khám phá thế giới rộng lớn bên ngoài. Ngoài ra, sữa Frisolac Gold 3 cung cấp các dưỡng chất quan trọng hỗ trợ tăng trưởng và sự phát triển toàn diện của trẻ như Vitamin D, Taurin, Selen, DHA, Prebiotics, Probiotics và Canxi. Sản phẩm hoàn toàn không có chất bảo quản, chất tạo mùi nên bạn có thể yên tâm về chất lượng và tuyệt đối an toàn cho bé.</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/SEO/Sua-cho-be/sua-frisolac-gold-3-850g-1-2-tuoi.jpg"></em></p><p><em>Sữa Frisolac Gold 3 850g cho bé 1-2 tuổi mẫu mới</em></p><h2><strong>Thành phần của sữa Frisolac Gold 3 cho bé 1-2 tuổi</strong></h2><p>&nbsp;</p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/SEO/Sua-cho-be/sua-frisolac-gold-3-850g-1-den-2-tuoi.jpg"></em></p><p><em>Thành phần dinh dưỡng trong sữa Frisolac Gold 3 850g cho bé 1-2 tuổi</em></p><h3><strong>Ưu điểm vượt trội của sữa Frisolac Gold 3 850g</strong></h3><p><a href="https://www.kidsplaza.vn/tag/sua-frisolac-gold" rel="noopener noreferrer" target="_blank"><strong>Sữa Frisolac&nbsp;Gold</strong></a><strong>&nbsp;3 850g&nbsp;</strong>mới là sự kết hợp tối ưu giữa công nghệ&nbsp;<strong>LockNutri</strong>&nbsp;và dưỡng chất thiên nhiên hỗ trợ cho bé hệ miễn dịch và tiêu hóa khỏe mạnh.</p><p><strong>Sữa Frisolac Gold 3 có dưỡng chất từ thiên nhiên:</strong></p><ul><li><strong>NOVAS Signature Milk</strong>&nbsp;- Nguồn sữa chất lượng tại trang trại Hà Lan của chúng tôi.</li><li><br></li><li><strong>Sữa Frisolac Gold số 3 850g&nbsp;</strong>được sản xuất bằng&nbsp;<strong>100% nguồn sữa từ giống bò sữa Friesian&nbsp;</strong>được chăn nuôi, chăm sóc bởi các gia đình nông dân Hà lan có hơn 145 năm kinh nghiệm.</li></ul>', 0, 565000, 500000, 6, 6, 3, 1, N'2024-07-04 12:33:56.0000000', null, 2, N'2024-07-24 04:39:37.3865703', N'https://i.imgur.com/DGqxOSK.jpeg', 0x0000000000003ADF);
INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'1C9E1E59-59E2-458F-BE5B-F176EF725669', N'Lốc 4 hộp sữa Milo Active Go 180ml cho bé trên 6 tuổi', N'<p>Sữa Milo được nghiên cứu và phát triển bởi Nestlé Thuỵ Sĩ, là sự kết hợp hoàn hảo từ hương vị thơm ngon của ca cao cùng&nbsp;nguồn dưỡng chất&nbsp;từ sữa, mầm lúa mạch nguyên cám, các vitamin, khoáng chất.</p><h2>"Tiếp sức giờ ra chơi</h2><p><em><img src="https://cdn.tgdd.vn/Products/Images/2945/84361/bhx/loc-4-hop-sua-lua-mach-milo-180ml-202404051441132090.jpg"><img src="https://cdn.tgdd.vn/Products/Images//2945/84361/bhx/files/thuc-uong-dd-milo-180ml-1.png"></em></p><p><em>Thức uống dinh dưỡng&nbsp;Milo được nghiên cứu và phát triển bởi Nestlé Thụy Sĩ, cung cấp dưỡng chất cân bằng và đầy đủ, cho bé luôn khỏe mạnh.</em></p><p><em>&nbsp;</em></p><p><em><img src="https://cdn.tgdd.vn/Products/Images//2945/84361/bhx/files/thuc-uong-dd-milo-180ml-2.png"></em></p>', 956, 33000, 0, 22, 4, 22, 1, N'2024-06-29 09:59:16.0000000', null, 1, N'2024-07-23 03:11:45.4983986', N'https://i.imgur.com/SKQvrxb.jpeg', 0x00000000000039D6);
