INSERT INTO yumilk.dbo.products (Id, name, description, quantity, original_price, sale_price, category_id, brand_id, unit_id, is_active, created_at, deleted_at, status_id, modified_at, thumbnail, version) VALUES (N'3B1DC680-43B4-4320-B0C7-FFDE2E20C5EC', N'Sữa Nan Organic số 2 900gr cho bé từ 6-24 tháng tuổi', N'<h2><strong>Sữa bột Nan Organic số 3 900gr cho bé từ 2-6 tuổi</strong></h2><p><strong>Sữa bột Nan</strong><strong style="background-color: var(--chakra-colors-brand-secondary); color: var(--chakra-colors-chakra-body-text);">&nbsp;Organic số 3&nbsp;900gr</strong><span style="background-color: var(--chakra-colors-brand-secondary); color: var(--chakra-colors-chakra-body-text);">&nbsp;là sản phẩm dinh dưỡng công thức hữu cơ dành cho trẻ từ 2-6 tuổi tuổi được chứng nhận hữu cơ của NASAA.&nbsp;</span><strong style="background-color: var(--chakra-colors-brand-secondary); color: var(--chakra-colors-chakra-body-text);">NAN ORGANIC 3</strong><span style="background-color: var(--chakra-colors-brand-secondary); color: var(--chakra-colors-chakra-body-text);">&nbsp;cung cấp cho trẻ các chất dinh dưỡng hỗ trợ cho sự phát triển khỏe mạnh về thể chất và trí não.</span></p><p><em><img src="https://cdn-v2.kidsplaza.vn/media/wysiwyg/SEO/Sua-cho-be/sua-nan-organic-3-900g.jpg">Sữa Nan Organic&nbsp;3 900g cho bé từ 2-6 tuổi tuổi</em></p><h3><strong>Thành phần sữa bột Nan Organic 3 900gr</strong></h3><p><strong>Sữa bột Nan Organic số 3 900gr</strong>&nbsp;bao gồm các thành phần: LACTOSE hữu cơ, SỮA tách béo (skimmed MILK) hữu cơ, Dầu hướng dương giàu Oleic, Maltodextrin, ĐẠM WHEY (WHEY PROTEIN) hữu cơ, Dầu hạt cải có hàm lượng axit Erucic thấp, Fructo-oligosacarit, Dầu hướng dương, Kali citrate, Trisodium Citrate Dihydrate, Canxi hydro Phosphate dehydrate, Kali Clorua, Canxi Hydroxit, Vitamin C, Chất nhũ hóa Lecithin ĐẬU NÀNH (SOYA lecithin), Magiê Chloride Hexahydrate, Natri hydro cacbonat, Dầu tảo giàu DHA, Sắt Sulfate Heptahydrate, Dầu nấm giàu ARA, Chất điều chỉnh độ axit axit Citric, Kẽm sulfat, Nicotinamide, Chất chống oxy hóa hỗn hợp Tocopherol, Vitamin E, Dầu ĐẬU NÀNH (SOYA bean oil), Vitamin B5, Vitamin A, Vitamin B1, Đồng sulfat Pentahydrate, Vitamin B6, Vitamin D3, Axit Folic, Kali iođua, Vitamin K1, Chất chống oxy hóa Ascorbyl Palmitate, Biotin, Vitamin B12.</p>', 992, 599000, 0, 21, 4, 6, 1, N'2024-06-29 09:42:43.0000000', null, 1, N'2024-07-23 03:12:50.4453358', N'https://i.imgur.com/wg60CPw.jpeg', 0x00000000000039D7);
